shared_code.value:
#if CH_CFG_USE_HEAP
static memory_heap_t heap1;
#endif
#if CH_CFG_USE_MEMPOOLS
static memory_pool_t mp1;
#endif

static THD_FUNCTION(dyn_thread1, p) {

  test_emit_token(*(char *)p);
}

local_variables.value:
size_t n1, total1, largest1;
size_t n2, total2, largest2;
tprio_t prio;

code.value:
threads[0] = chThdCreateFromHeap(&heap1,
                                 THD_WORKING_AREA_SIZE(THREADS_STACK_SIZE),
                                 "dyn1",
                                 prio-1, dyn_thread1, "A");
test_assert(threads[0] != NULL, "thread creation failed");

threads[1] = chThdCreateFromHeap(&heap1,
                                 THD_WORKING_AREA_SIZE(THREADS_STACK_SIZE),
                                 "dyn2",
                                 prio-2, dyn_thread1, "B");
test_assert(threads[1] != NULL, "thread creation failed");

threads[2] = chThdCreateFromHeap(&heap1,
                                 (((size_t)-1) >> 1U) + 1U,
                                 "dyn3",
                                 prio-3, dyn_thread1, "C");
test_assert(threads[2] == NULL, "thread creation not failed");

n2 = chHeapStatus(&heap1, &total2, &largest2);
test_assert(n1 == n2, "fragmentation changed");
test_assert(total1 == total2, "total free space changed");
test_assert(largest1 == largest2, "largest fragment size changed");

threads[0] = chThdCreateFromMemoryPool(&mp1, "dyn1", prio-1, dyn_thread1, "A");
threads[1] = chThdCreateFromMemoryPool(&mp1, "dyn2", prio-2, dyn_thread1, "B");
threads[2] = chThdCreateFromMemoryPool(&mp1, "dyn3", prio-3, dyn_thread1, "C");
threads[3] = chThdCreateFromMemoryPool(&mp1, "dyn4", prio-4, dyn_thread1, "D");
threads[4] = chThdCreateFromMemoryPool(&mp1, "dyn5", prio-5, dyn_thread1, "E");

for (i = 0; i < 4; i++)
  test_assert(chPoolAlloc(&mp1) != NULL, "pool list empty");
test_assert(chPoolAlloc(&mp1) == NULL, "pool list not empty");

teardown_code.value:
{
  thread_t *tp, *ntp;

  tp = chRegFirstThread();
  do {
    ntp = chRegNextThread(tp);
    tp = ntp;
  } while (tp != NULL);
}
chHeapObjectDispose(&heap1);

local_variables.value:
size_t n1, total1, largest1;
size_t n2, total2, largest2;
size_t n3, total3, largest3;
thread_t *tp, *ntp, *dtp;
tprio_t prio;
bool found;

code.value:
prio = chThdGetPriorityX();
n1 = chHeapStatus(&heap1, &total1, &largest1);
test_assert(n1 == 1, "heap fragmented");

dtp = chThdCreateFromHeap(&heap1,
                            THD_WORKING_AREA_SIZE(THREADS_STACK_SIZE),
                            "dyn-detached",
                            prio-1, dyn_thread1, "D");
test_assert(dtp != NULL, "thread creation failed");
threads[0] = dtp;
chThdRelease(dtp);
threads[0] = NULL;

chThdSleepMilliseconds(50);
test_assert_sequence("D", "invalid sequence");
n2 = chHeapStatus(&heap1, &total2, &largest2);
test_assert(total2 < total1, "memory already recovered");
(void)n2;
(void)largest2;

found = false;
tp = chRegFirstThread();
do {
  if (tp == dtp) {
    found = true;
  }
  ntp = chRegNextThread(tp);
  tp = ntp;
} while (tp != NULL);

test_assert(found, "not found in registry scan");
n3 = chHeapStatus(&heap1, &total3, &largest3);
test_assert(n1 == n3, "fragmentation changed");
test_assert(total1 == total3, "total free space changed");
test_assert(largest1 == largest3, "largest fragment size changed");

shared_code.value:
#if CH_CFG_USE_SEMAPHORES || defined(__DOXYGEN__)
static semaphore_t sem1;
#endif
#if CH_CFG_USE_MUTEXES || defined(__DOXYGEN__)
static mutex_t mtx1;
#endif

static void tmo(virtual_timer_t *vtp, void *param) {

  (void)vtp;
  (void)param;
}

static virtual_timer_t vt1, vt2;
static volatile uint32_t vt_counter;

static void vt_continuous_cb(virtual_timer_t *vtp, void *param) {

  (void)vtp;
  (void)param;

  vt_counter++;
}

#if CH_CFG_USE_MESSAGES
static THD_FUNCTION(bmk_thread1, p) {
  thread_t *tp;
  msg_t msg;

  (void)p;
  do {
    tp = chMsgWait();
    msg = chMsgGet(tp);
    chMsgRelease(tp, msg);
  } while (msg);
}

NOINLINE static unsigned int msg_loop_test(thread_t *tp) {
  systime_t start, end;

  uint32_t n = 0;
  start = test_wait_tick();
  end = chTimeAddX(start, TIME_MS2I(1000));
  do {
    (void)chMsgSend(tp, 1);
    n++;
#if defined(SIMULATOR)
    _sim_check_for_interrupts();
#endif
  } while (chVTIsSystemTimeWithinX(start, end));
  (void)chMsgSend(tp, 0);
  return n;
}
#endif

static THD_FUNCTION(bmk_thread3, p) {

  chThdExit((msg_t)p);
}

static THD_FUNCTION(bmk_thread4, p) {
  msg_t msg;
  thread_t *self = chThdGetSelfX();

  (void)p;
  chSysLock();
  do {
    chSchGoSleepS(CH_STATE_SUSPENDED);
    msg = self->u.rdymsg;
  } while (msg == MSG_OK);
  chSysUnlock();
}

#if CH_CFG_USE_SEMAPHORES
static THD_FUNCTION(bmk_thread7, p) {

  (void)p;
  while (!chThdShouldTerminateX())
    chSemWait(&sem1);
}
#endif

static THD_FUNCTION(bmk_thread8, p) {

  do {
    chThdYield();
    chThdYield();
    chThdYield();
    chThdYield();
    (*(uint32_t *)p) += 4;
#if defined(SIMULATOR)
    _sim_check_for_interrupts();
#endif
  } while(!chThdShouldTerminateX());
}

